/**
 * Decodes a base64 string into a Uint8Array.
 */
export function decode(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

/**
 * Encodes a Uint8Array into a base64 string.
 */
export function encode(bytes: Uint8Array): string {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

/**
 * Decodes raw PCM audio data into an AudioBuffer for playback.
 */
export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

import { GoogleGenAI, LiveServerMessage, Modality, Blob } from '@google/genai';
import { encode, decode, decodeAudioData } from '../utils/audioUtils';

// Constants for audio handling
const INPUT_SAMPLE_RATE = 16000;
const OUTPUT_SAMPLE_RATE = 24000;

export interface LisaaCallbacks {
  onOpen: () => void;
  onClose: () => void;
  onError: (error: any) => void;
  onTranscript: (text: string, isUser: boolean) => void;
  onVolumeChange: (volume: number) => void;
}

export class LisaaService {
  private ai: any;
  private session: any;
  private inputAudioContext: AudioContext | null = null;
  private outputAudioContext: AudioContext | null = null;
  private sources: Set<AudioBufferSourceNode> = new Set();
  private nextStartTime: number = 0;
  private scriptProcessor: ScriptProcessorNode | null = null;
  private analyser: AnalyserNode | null = null;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: (process.env.API_KEY as string) });
  }

  async connect(callbacks: LisaaCallbacks) {
    try {
      this.inputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: INPUT_SAMPLE_RATE });
      this.outputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: OUTPUT_SAMPLE_RATE });

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      const sessionPromise = this.ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            const source = this.inputAudioContext!.createMediaStreamSource(stream);
            this.scriptProcessor = this.inputAudioContext!.createScriptProcessor(4096, 1, 1);

            // For volume visualization
            this.analyser = this.inputAudioContext!.createAnalyser();
            this.analyser.fftSize = 256;
            source.connect(this.analyser);

            const dataArray = new Uint8Array(this.analyser.frequencyBinCount);
            const updateVolume = () => {
              if (this.analyser) {
                this.analyser.getByteFrequencyData(dataArray);
                const average = dataArray.reduce((a, b) => a + b) / dataArray.length;
                callbacks.onVolumeChange(average / 128); // Normalized 0-1
                requestAnimationFrame(updateVolume);
              }
            };
            updateVolume();

            this.scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const pcmBlob = this.createBlob(inputData);
              sessionPromise.then((session: any) => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };

            source.connect(this.scriptProcessor);
            this.scriptProcessor.connect(this.inputAudioContext!.destination);
            callbacks.onOpen();
          },
          onmessage: async (message: LiveServerMessage) => {
            // Handle Transcripts
            if (message.serverContent?.outputTranscription) {
              callbacks.onTranscript(message.serverContent.outputTranscription.text, false);
            } else if (message.serverContent?.inputTranscription) {
              callbacks.onTranscript(message.serverContent.inputTranscription.text, true);
            }

            // Handle Audio Playback
            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio && this.outputAudioContext) {
              this.nextStartTime = Math.max(this.nextStartTime, this.outputAudioContext.currentTime);
              const audioBuffer = await decodeAudioData(
                decode(base64Audio),
                this.outputAudioContext,
                OUTPUT_SAMPLE_RATE,
                1
              );

              const source = this.outputAudioContext.createBufferSource();
              source.buffer = audioBuffer;
              const gainNode = this.outputAudioContext.createGain();
              source.connect(gainNode);
              gainNode.connect(this.outputAudioContext.destination);

              source.addEventListener('ended', () => {
                this.sources.delete(source);
              });

              source.start(this.nextStartTime);
              this.nextStartTime += audioBuffer.duration;
              this.sources.add(source);
            }

            // Handle Interruptions
            if (message.serverContent?.interrupted) {
              this.sources.forEach(s => {
                try { s.stop(); } catch(e) {}
              });
              this.sources.clear();
              this.nextStartTime = 0;
            }
          },
          onerror: (e: any) => callbacks.onError(e),
          onclose: () => callbacks.onClose(),
        },
        config: {
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          outputAudioTranscription: {},
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
          },
          systemInstruction: `You are "Lisaa," a friendly, enthusiastic, and highly knowledgeable AI Physics Specialist.
Your goal is to make physics fascinating, accessible, and easy to understand for everyone.
CORE RULES:
1. Physics Expert: Explain Newton's Laws to Quantum Mechanics, Astrophysics, and Thermodynamics.
2. Bilingual: Fluently speak English and Bengali. Respond in the user's detected language. Use "Banglish" if appropriate.
3. Voice-First: Keep responses conversational, rhythmic, and break down complex ideas. No monologues.
4. Teacher: Use analogies (e.g., voltage = water pressure). Be encouraging.
5. Interaction: ALWAYS end with a relevant follow-up question to keep the conversation flowing.
6. Safety: ONLY discuss physics and related science. Politely steer non-science questions back to physics.
7. Math: Describe formulas conceptually. Explain the logic of calculations.`,
        },
      });

      this.session = await sessionPromise;
    } catch (err) {
      callbacks.onError(err);
    }
  }

  private createBlob(data: Float32Array): Blob {
    const l = data.length;
    const int16 = new Int16Array(l);
    for (let i = 0; i < l; i++) {
      int16[i] = data[i] * 32768;
    }
    return {
      data: encode(new Uint8Array(int16.buffer)),
      mimeType: 'audio/pcm;rate=16000',
    };
  }

  disconnect() {
    if (this.session) {
      this.session.close();
      this.session = null;
    }
    if (this.scriptProcessor) {
      this.scriptProcessor.disconnect();
      this.scriptProcessor = null;
    }
    if (this.inputAudioContext) {
      this.inputAudioContext.close();
      this.inputAudioContext = null;
    }
    if (this.outputAudioContext) {
      this.outputAudioContext.close();
      this.outputAudioContext = null;
    }
    this.analyser = null;
    this.sources.forEach(s => {
      try { s.stop(); } catch(e) {}
    });
    this.sources.clear();
  }
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { LisaaService } from '../services/geminiLiveService';

interface Message {
  text: string;
  isUser: boolean;
  timestamp: number;
}

const LisaaInterface: React.FC = () => {
  const [isConnected, setIsConnected] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [volume, setVolume] = useState(0);
  const [messages, setMessages] = useState<Message[]>([]);

  const serviceRef = useRef<LisaaService | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const toggleConnection = useCallback(async () => {
    if (isConnected) {
      serviceRef.current?.disconnect();
      setIsConnected(false);
      return;
    }

    setIsConnecting(true);
    setError(null);

    try {
      if (!serviceRef.current) {
        serviceRef.current = new LisaaService();
      }

      await serviceRef.current.connect({
        onOpen: () => {
          setIsConnected(true);
          setIsConnecting(false);
        },
        onClose: () => {
          setIsConnected(false);
          setIsConnecting(false);
        },
        onError: (err) => {
          console.error('Lisaa Error:', err);
          setError('Failed to connect to Lisaa. Please check your mic and try again.');
          setIsConnected(false);
          setIsConnecting(false);
        },
        onTranscript: (text, isUser) => {
          setMessages(prev => {
            const last = prev[prev.length - 1];
            // Update last message if it's the same sender and same "burst"
            if (last && last.isUser === isUser && Date.now() - last.timestamp < 3000) {
              const updated = [...prev];
              updated[updated.length - 1] = { ...last, text: last.text + ' ' + text };
              return updated;
            }
            return [...prev, { text, isUser, timestamp: Date.now() }];
          });
        },
        onVolumeChange: (vol) => {
          setVolume(vol);
        }
      });
    } catch (err) {
      setError('An unexpected error occurred.');
      setIsConnecting(false);
    }
  }, [isConnected]);

  return (
    <div className="flex flex-col h-[70vh] bg-slate-900/40 backdrop-blur-xl border border-slate-700/50 rounded-3xl overflow-hidden physics-glow shadow-2xl">
      {/* Visualizer Area */}
      <div className="relative flex-1 flex flex-col items-center justify-center p-8 overflow-hidden">
        {/* Animated Background Orbs */}
        <div className="absolute inset-0 z-0">
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-64 h-64 bg-sky-500/10 rounded-full blur-3xl animate-pulse" />
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-48 h-48 bg-indigo-500/10 rounded-full blur-2xl animate-pulse" style={{ animationDelay: '1s' }} />
        </div>

        {/* Main Voice Orb */}
        <div className="relative z-10 flex flex-col items-center gap-8">
          <div 
            className={`
              w-32 h-32 rounded-full flex items-center justify-center transition-all duration-300
              ${isConnected ? 'bg-gradient-to-br from-sky-400 to-indigo-500' : 'bg-slate-800'}
              ${isConnected ? 'physics-glow shadow-sky-500/50' : 'shadow-none'}
            `}
            style={{ 
              transform: `scale(${1 + volume * 0.5})`,
              boxShadow: isConnected ? `0 0 ${40 + volume * 80}px rgba(56, 189, 248, ${0.3 + volume * 0.4})` : 'none'
            }}
          >
            {isConnecting ? (
              <div className="w-8 h-8 border-4 border-white/20 border-t-white rounded-full animate-spin" />
            ) : isConnected ? (
              <svg className="w-12 h-12 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
              </svg>
            ) : (
              <svg className="w-12 h-12 text-slate-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5.636 18.364a9 9 0 010-12.728m12.728 0a9 9 0 010 12.728m-9.9-2.828a5 5 0 010-7.072m7.072 0a5 5 0 010 7.072M13 12a1 1 0 11-2 0 1 1 0 012 0z" />
              </svg>
            )}
          </div>

          <div className="text-center">
            <h2 className="text-2xl font-bold text-white mb-2">
              {isConnecting ? 'Waking up Lisaa...' : isConnected ? 'Lisaa is Listening' : 'Lisaa is Resting'}
            </h2>
            <p className="text-slate-400 max-w-sm">
              {isConnected 
                ? 'Ask anything about the universe! English or Bengali - I speak both.' 
                : 'Tap the button below to start your physics conversation.'}
            </p>
          </div>
        </div>

        {/* Error Message */}
        {error && (
          <div className="absolute top-4 left-4 right-4 bg-red-500/10 border border-red-500/20 text-red-400 p-3 rounded-lg text-sm flex items-center gap-2 animate-in fade-in slide-in-from-top-4">
            <svg className="w-4 h-4 shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
            {error}
          </div>
        )}
      </div>

      {/* Transcription Area */}
      {isConnected && messages.length > 0 && (
        <div className="h-48 border-t border-slate-700/50 bg-slate-950/30 overflow-y-auto p-4 space-y-4">
          {messages.map((m, i) => (
            <div key={i} className={`flex flex-col ${m.isUser ? 'items-end' : 'items-start'}`}>
              <div className={`
                max-w-[80%] px-4 py-2 rounded-2xl text-sm leading-relaxed
                ${m.isUser 
                  ? 'bg-slate-800 text-slate-200 rounded-tr-none' 
                  : 'bg-sky-500/10 text-sky-200 border border-sky-500/20 rounded-tl-none'}
              `}>
                {m.text}
              </div>
            </div>
          ))}
          <div ref={messagesEndRef} />
        </div>
      )}

      {/* Controls */}
      <div className="p-6 bg-slate-950/50 border-t border-slate-700/50 flex justify-center">
        <button
          onClick={toggleConnection}
          disabled={isConnecting}
          className={`
            relative group px-12 py-4 rounded-full font-bold transition-all duration-500
            ${isConnected 
              ? 'bg-red-500/10 text-red-400 border border-red-500/30 hover:bg-red-500/20' 
              : 'bg-sky-500 text-slate-900 border border-sky-400 hover:bg-sky-400 physics-glow'}
            disabled:opacity-50 disabled:cursor-not-allowed
          `}
        >
          <div className="flex items-center gap-3">
            <div className={`w-3 h-3 rounded-full ${isConnected ? 'bg-red-500 animate-pulse' : 'bg-slate-900'}`} />
            {isConnected ? 'END CONVERSATION' : 'START PHYSICS TALK'}
          </div>
          {!isConnected && (
            <div className="absolute inset-0 bg-white/20 rounded-full scale-0 group-hover:scale-100 transition-transform duration-500 origin-center" />
          )}
        </button>
      </div>
    </div>
  );
};

export default LisaaInterface;
